const [isHydrated, setIsHydrated] = useState(false)
useEffect(() => {
  loadGame().then(result => {
    if (result.save) {
      useGameStore.getState().hydrate(result.save)
      useInventoryStore.getState().hydrateEquipped(result.save.equipped)
      useInventoryStore.getState().hydrateEquippedByClass(result.save.equippedByClass ?? {})
      useCombatStore.setState({ townPortalScrolls: result.save.townPortalScrolls })
    }
    setIsHydrated(true)
  })
}, [])
if (!isHydrated) return <LoadingScreen />
